select
    t.task_id, t.ent_code, t.out_put_id, t.template_code, t.task_type, t.task_status, t.task_desc, t.plan_date, t.early_days,
    t.operator, t.assign_time, t.remark, t.create_id, t.create_time, t.update_time,
    e.ent_name, o.out_put_code, o.out_put_name, u.user_name as operator_name, u.nick_name as operator_nick, u1.user_name as create_name, u1.nick_name as create_nick
from t_ops_task t
left join t_bas_enterprise e on e.ent_code = t.ent_code
left join t_ent_out_put_info o on o.out_put_id = t.out_put_id
left join sys_user u on u.user_id = t.operator
left join sys_user u1 on u1.user_id = t.create_id


    t.operator = #{operator} and t.task_status in (2, 3)


            and t.ent_code = #{entCode}


            and t.ent_code in

                #{entCode}




        and (e.region = #{region} or e.region like CONCAT(#{region}, ',%'))


        and t.out_put_id = #{outPutId}


        and t.template_code = #{templateCode}


        and t.task_type = #{taskType}


        and t.plan_date between #{taskStart} and #{taskEnd}


order by t.task_id desc

